parameters.jsCode:
// Extract workflow JSON from LLM response
const body = $json;
const choice = body.choices && body.choices[0] ? body.choices[0] : null;
const message = choice ? choice.message : null;
const content = message ? message.content : '';

// Extract JSON from response (handle markdown code blocks)
let workflowJson = content;

// Remove markdown code block markers if present
if (workflowJson.includes('```json')) {
  workflowJson = workflowJson.split('```json')[1];
  if (workflowJson.includes('```')) {
    workflowJson = workflowJson.split('```')[0];
  }
} else if (workflowJson.includes('```')) {
  const parts = workflowJson.split('```');
  if (parts.length >= 2) {
    workflowJson = parts[1];
  }
}

try {
  // Parse the workflow JSON
  const parsed = JSON.parse(workflowJson);

  // Extract just the workflow object if wrapped
  const workflow = parsed.workflow || parsed;

  return [{
    json: {
      success: true,
      workflow: workflow,
      raw_response: content,
      model: body.model || 'unknown',
      timestamp: new Date().toISOString()
    },
    binary: {
      workflow_json: {
        data: Buffer.from(JSON.stringify(workflow)),
        mimeType: 'application/json'
      }
    }
  }];
} catch (error) {
  return [{
    json: {
      success: false,
      error: error.message,
      raw_response: content,
      timestamp: new Date().toISOString()
    }
  }];
}

// Process ComfyUI response
const body = $json;
const promptId = body.prompt_id || body.id || 'unknown';
const node_ids = body.node_ids || [];

return [{
  json: {
    success: true,
    prompt_id: promptId,
    nodes_queued: node_ids.length,
    timestamp: new Date().toISOString()
  }
}];
